          verb = verb_map.get(t.predicate, "has")
          subject_map[t.subject].append(f"{verb} {t.object}")

      parts = []
      for subj, actions in subject_map.items():
          if len(actions) == 1:
              parts.append(f"{subj} {actions[0]}")
          else:
              # Join multiple actions with commas and an 'and' before the last one
              if len(actions) == 2:
                  actions_str = " and ".join(actions)
              else:
                  actions_str = ", ".join(actions[:-1]) + ", and " + actions[-1]
              parts.append(f"{subj} {actions_str}")

      # Combine different subjects with semicolons and finish with a period
      return "; ".join(parts) + "."
with:
  # Build a single fluent sentence from all triples
      phrases = []
      for t in triples:
          verb = verb_map.get(t.predicate, "has")
          obj = t.object

          # Add simple units for numeric values when predicate indicates a measurement
          if isinstance(obj, (int, float)):
              if "Feet" in t.predicate:
                  obj = f"{obj} feet"
              elif "Metre" in t.predicate or "Metres" in t.predicate:
                  obj = f"{obj} metres"
              elif "elevationAboveTheSeaLevel" in t.predicate:
                  obj = f"{obj} metres"
          phrases.append(f"{t.subject} {verb} {obj}")

      if not phrases:
          return ""

      if len(phrases) == 1:
          sentence = phrases[0]
      elif len(phrases) == 2:
          sentence = " and ".join(phrases)
      else:
          sentence = ", ".join(phrases[:-1]) + ", and " + phrases[-1]

      return sentence + "."
